#include <stdio.h>
#include <stdlib.h>
#define MAXN 300
#define MAXM 50000

// Define the graph structure
typedef struct {
    int u, v;
} Edge;

// Define the graph
Edge edges[MAXM];
int n, m;

// Define the DFS function
void dfs(int u, int parent, int *disc, int *low, int *time, int *isBridge) {
    static int time = 0;
    disc[u] = low[u] = time++;
    for (int i = 0; i < m; i++) {
        int v = edges[i].u == u ? edges[i].v : edges[i].u;
        if (v == parent) continue;
        if (disc[v] == -1) {
            dfs(v, u, disc, low, time, isBridge);
            low[u] = min(low[u], low[v]);
            if (low[v] > disc[u]) isBridge[i] = 1;
        } else {
            low[u] = min(low[u], disc[v]);
        }
    }
}

int main() {
    // Read input
    scanf("%d %d", &n, &m);
    for (int i = 0; i < m; i++) {
        scanf("%d %d", &edges[i].u, &edges[i].v);
    }

    // Initialize variables
    int disc[MAXN], low[MAXN], time = 0, isBridge[MAXM];
    for (int i = 0; i < n; i++) disc[i] = -1;
    for (int i = 0; i < m; i++) isBridge[i] = 0;

    // Perform DFS
    for (int i = 0; i < n; i++) {
        if (disc[i] == -1) dfs(i, -1, disc, low, &time, isBridge);
    }

    // Count critical intersections
    int count = 0;
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            if (isBridge[j] && (edges[j].u == i || edges[j].v == i)) {
                count++;
                break;
            }
        }
    }

