    printf("%d\n", count);
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            if (isBridge[j] && (edges[j].u == i || edges[j].v == i)) {
                printf("%d\n", i + 1);
                break;
            }
        }
    }

    return 0;
}

